import 'package:cloud_firestore/cloud_firestore.dart'; import 'package:firebase_auth/firebase_auth.dart'; import 'package:flutter/material.dart'; import '../services/firestore_service.dart';
class RemindersScreen extends StatefulWidget { const RemindersScreen({super.key}); @override State<RemindersScreen> createState()=>_RemindersScreenState(); }
class _RemindersScreenState extends State<RemindersScreen>{ final service=FirestoreService(); Future<void> showAddReminderDialog() async { final title=TextEditingController(), desc=TextEditingController(), course=TextEditingController(), date=TextEditingController(), time=TextEditingController(); await showDialog(context: context, builder:(_)=>AlertDialog(title: const Text('Create Reminder'), content: SingleChildScrollView(child: Column(children:[TextField(controller:title,decoration: const InputDecoration(labelText:'Title')),TextField(controller:desc,decoration: const InputDecoration(labelText:'Description')),TextField(controller:course,decoration: const InputDecoration(labelText:'Course Code')),TextField(controller:date,decoration: const InputDecoration(labelText:'Date e.g. 2026-06-19')),TextField(controller:time,decoration: const InputDecoration(labelText:'Time e.g. 09:00'))])), actions:[TextButton(onPressed:()=>Navigator.pop(context), child: const Text('Cancel')), ElevatedButton(onPressed:() async { await service.createReminder(userId: FirebaseAuth.instance.currentUser?.uid??'', title:title.text, description:desc.text, courseCode:course.text, reminderDate:date.text, reminderTime:time.text); if(mounted) Navigator.pop(context);}, child: const Text('Save'))])); for(final c in [title,desc,course,date,time]){c.dispose();} }
@override Widget build(BuildContext context){ final userId=FirebaseAuth.instance.currentUser?.uid??''; return Scaffold(appBar: AppBar(title: const Text('Reminders')), floatingActionButton: FloatingActionButton(onPressed: showAddReminderDialog, child: const Icon(Icons.add)), body: StreamBuilder<QuerySnapshot<Map<String,dynamic>>>(stream: service.streamUserReminders(userId), builder:(context,snapshot){ if(snapshot.hasError) return Center(child: Text('Error: ${snapshot.error}')); if(!snapshot.hasData) return const Center(child:CircularProgressIndicator()); final docs=snapshot.data!.docs; if(docs.isEmpty) return const Center(child:Text('No reminders yet.')); return ListView.builder(padding: const EdgeInsets.all(16), itemCount: docs.length, itemBuilder:(context,index){ final d=docs[index].data(); return Card(child: ListTile(leading: const Icon(Icons.notifications,color:Colors.red), title: Text(d['title']??'Untitled Reminder'), subtitle: Text('${d['description']??''}\n${d['reminderDate']??'-'} at ${d['reminderTime']??'-'}'), isThreeLine:true, trailing: Chip(label: Text(d['createdBy']??'user')))); }); })); }}
